import{_ as t,o,c as e,ae as r}from"./chunks/framework.C8MNLDzb.js";const c=JSON.parse('{"title":"子部代表作者","description":"","frontmatter":{},"headers":[],"relativePath":"docs/sucai/zuozhe/zi/子部作者.md","filePath":"docs/sucai/zuozhe/zi/子部作者.md"}'),h={name:"docs/sucai/zuozhe/zi/子部作者.md"};function u(i,a,l,q,n,d){return o(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="子部代表作者" tabindex="-1">子部代表作者 <a class="header-anchor" href="#子部代表作者" aria-label="Permalink to &quot;子部代表作者&quot;">​</a></h1><h2 id="老子-约公元前571年-公元前471年" tabindex="-1">老子（约公元前571年-公元前471年） <a class="header-anchor" href="#老子-约公元前571年-公元前471年" aria-label="Permalink to &quot;老子（约公元前571年-公元前471年）&quot;">​</a></h2><p>姓李名耳，字伯阳，谥号聃，春秋时期楚国苦县人。道家学派创始人，著《道德经》五千言，主张&quot;道法自然&quot;，&quot;无为而治&quot;，是中国古代伟大的哲学家。</p><h2 id="庄子-约公元前369年-公元前286年" tabindex="-1">庄子（约公元前369年-公元前286年） <a class="header-anchor" href="#庄子-约公元前369年-公元前286年" aria-label="Permalink to &quot;庄子（约公元前369年-公元前286年）&quot;">​</a></h2><p>名周，字子休，宋国蒙人，战国时期道家学派代表人物。与老子并称&quot;老庄&quot;，著《庄子》一书，想象丰富，文笔汪洋恣肆，是道家思想的集大成者。</p><h2 id="孔子-公元前551年-公元前479年" tabindex="-1">孔子（公元前551年-公元前479年） <a class="header-anchor" href="#孔子-公元前551年-公元前479年" aria-label="Permalink to &quot;孔子（公元前551年-公元前479年）&quot;">​</a></h2><p>名丘，字仲尼，春秋时期鲁国陬邑人。儒家学派创始人，中国古代伟大的思想家、教育家、政治家。整理《诗》《书》《礼》《乐》《易》《春秋》，删修《春秋》，是中国文化的奠基人。</p><h2 id="孟子-约公元前372年-公元前289年" tabindex="-1">孟子（约公元前372年-公元前289年） <a class="header-anchor" href="#孟子-约公元前372年-公元前289年" aria-label="Permalink to &quot;孟子（约公元前372年-公元前289年）&quot;">​</a></h2><p>名轲，字子舆，战国时期邹国马邑人。儒家学派代表人物，被后世尊为&quot;亚圣&quot;。著《孟子》，主张&quot;性善论&quot;，提出&quot;民本&quot;思想。</p><h2 id="荀子-约公元前313年-公元前238年" tabindex="-1">荀子（约公元前313年-公元前238年） <a class="header-anchor" href="#荀子-约公元前313年-公元前238年" aria-label="Permalink to &quot;荀子（约公元前313年-公元前238年）&quot;">​</a></h2><p>名况，字卿，战国时期赵国人。儒家学派代表人物，提出&quot;性恶论&quot;，强调礼法并重。培养了韩非、李斯等法家人物。</p><h2 id="墨子-约公元前476年-公元前390年" tabindex="-1">墨子（约公元前476年-公元前390年） <a class="header-anchor" href="#墨子-约公元前476年-公元前390年" aria-label="Permalink to &quot;墨子（约公元前476年-公元前390年）&quot;">​</a></h2><p>名翟，春秋战国时期宋国（一说鲁国）人。墨家学派创始人。主张&quot;兼爱&quot;&quot;非攻&quot;&quot;尚贤&quot;&quot;节用&quot;，是中华文明中重视实践的学派。</p><h2 id="韩非-约公元前280年-公元前233年" tabindex="-1">韩非（约公元前280年-公元前233年） <a class="header-anchor" href="#韩非-约公元前280年-公元前233年" aria-label="Permalink to &quot;韩非（约公元前280年-公元前233年）&quot;">​</a></h2><p>姓韩名非，战国时期韩国人。法家学派集大成者，著《韩非子》。他综合商鞅的&quot;法&quot;、申不害的&quot;术&quot;、慎到的&quot;势&quot;，建立完整的法家思想体系。</p><h2 id="孙子-约公元前545年-公元前470年" tabindex="-1">孙子（约公元前545年-公元前470年） <a class="header-anchor" href="#孙子-约公元前545年-公元前470年" aria-label="Permalink to &quot;孙子（约公元前545年-公元前470年）&quot;">​</a></h2><p>名武，字长卿，春秋时期齐国人。中国古代伟大的军事家，著《孙子兵法》十三篇，是世界上最早的军事理论著作。</p><h2 id="列子-约公元前450年-公元前375年" tabindex="-1">列子（约公元前450年-公元前375年） <a class="header-anchor" href="#列子-约公元前450年-公元前375年" aria-label="Permalink to &quot;列子（约公元前450年-公元前375年）&quot;">​</a></h2><p>名列御寇，战国时期郑国人。道家学派代表人物，著《列子》，以寓言故事阐述道家哲理，想象丰富，语言简洁。</p><h2 id="杨朱-约公元前395年-公元前335年" tabindex="-1">杨朱（约公元前395年-公元前335年） <a class="header-anchor" href="#杨朱-约公元前395年-公元前335年" aria-label="Permalink to &quot;杨朱（约公元前395年-公元前335年）&quot;">​</a></h2><p>战国时期魏国人。思想家，主张&quot;为我&quot;&quot;贵己&quot;，被孟子批评为&quot;拔一毛而利天下不为也&quot;。是早期道家杨朱学派的代表。</p><h2 id="公孙龙-约公元前320年-公元前250年" tabindex="-1">公孙龙（约公元前320年-公元前250年） <a class="header-anchor" href="#公孙龙-约公元前320年-公元前250年" aria-label="Permalink to &quot;公孙龙（约公元前320年-公元前250年）&quot;">​</a></h2><p>姓公孙名龙，战国时期赵国人。名家学派代表人物，以&quot;白马非马&quot;&quot;离坚白&quot;等论辩著称，是中国逻辑学的先驱。</p><h2 id="鬼谷子-约公元前400年-公元前320年" tabindex="-1">鬼谷子（约公元前400年-公元前320年） <a class="header-anchor" href="#鬼谷子-约公元前400年-公元前320年" aria-label="Permalink to &quot;鬼谷子（约公元前400年-公元前320年）&quot;">​</a></h2><p>姓王名诩，号鬼谷子，战国时期楚国人。纵横家创始人，著《鬼谷子》，是纵横捭阖之术的鼻祖，相传苏秦、张仪都是他的学生。</p><h2 id="吕不韦-公元前235年" tabindex="-1">吕不韦（？-公元前235年） <a class="header-anchor" href="#吕不韦-公元前235年" aria-label="Permalink to &quot;吕不韦（？-公元前235年）&quot;">​</a></h2><p>战国末期阳翟大商人，后为秦相国。组织门客编撰《吕氏春秋》，兼采各家之说，是杂家学派的代表人物。</p><h2 id="刘安-公元前179年-公元前122年" tabindex="-1">刘安（公元前179年-公元前122年） <a class="header-anchor" href="#刘安-公元前179年-公元前122年" aria-label="Permalink to &quot;刘安（公元前179年-公元前122年）&quot;">​</a></h2><p>西汉沛县人，封为淮南王。组织门客编撰《淮南子》，以道家思想为主，兼收并蓄，是汉代杂家的代表作。</p><h2 id="王充-27年-约97年" tabindex="-1">王充（27年-约97年） <a class="header-anchor" href="#王充-27年-约97年" aria-label="Permalink to &quot;王充（27年-约97年）&quot;">​</a></h2><p>字仲任，东汉会稽上虞人。唯物主义哲学家，著《论衡》，批判鬼神迷信，提倡实事求是，是中国古代重要的唯物主义思想家。</p><h2 id="嵇康-224年-263年" tabindex="-1">嵇康（224年-263年） <a class="header-anchor" href="#嵇康-224年-263年" aria-label="Permalink to &quot;嵇康（224年-263年）&quot;">​</a></h2><p>字叔夜，三国时期魏国谯郡铚人。&quot;竹林七贤&quot;之一，玄学家，著《养生论》，主张&quot;越名教而任自然&quot;。</p><h2 id="葛洪-284年-364年" tabindex="-1">葛洪（284年-364年） <a class="header-anchor" href="#葛洪-284年-364年" aria-label="Permalink to &quot;葛洪（284年-364年）&quot;">​</a></h2><p>字孝龙，号抱朴子，东晋丹阳句容人。道教理论家，著《抱朴子》，外篇言理，内篇炼丹，是道教金丹派的重要人物。</p><h2 id="张载-1020年-1077年" tabindex="-1">张载（1020年-1077年） <a class="header-anchor" href="#张载-1020年-1077年" aria-label="Permalink to &quot;张载（1020年-1077年）&quot;">​</a></h2><p>字子厚，北宋凤翔郿县人。理学家，理学&quot;关学&quot;创始人，著《正蒙》，提出&quot;民胞物与&quot;思想，是宋代理学的重要人物。</p><h2 id="李贽-1527年-1602年" tabindex="-1">李贽（1527年-1602年） <a class="header-anchor" href="#李贽-1527年-1602年" aria-label="Permalink to &quot;李贽（1527年-1602年）&quot;">​</a></h2><p>号卓吾，别号温陵居士，明代福建泉州人。思想家、文学家，以&quot;童心说&quot;闻名，批判孔孟之道，是晚明思想解放的先驱。</p><h2 id="王夫之-1619年-1692年" tabindex="-1">王夫之（1619年-1692年） <a class="header-anchor" href="#王夫之-1619年-1692年" aria-label="Permalink to &quot;王夫之（1619年-1692年）&quot;">​</a></h2><p>字而农，号姜斋，明末清初衡州人。与顾炎武、黄宗羲并称&quot;清初三大儒&quot;，著《张子正蒙注》《读通鉴论》等，是中国古典哲学的总结性人物。</p>',41)])])}const p=t(h,[["render",u]]);export{c as __pageData,p as default};
